const Q_BIOLOGY_1998=[{"id": "objective>Biology>1998>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus is considered the central organelle of a cell because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contains the genetic material</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contains the nuclear sap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is bounded by the nuclear membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is located at the center of the cell</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus is considered the central organelle of a cell because it contains the genetic material. This genetic material, in the form of DNA, controls the activities of the cell and is responsible for inheritance. The other options are not the primary reasons why the nucleus is considered the central organelle.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1998>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The procaryotic cell type is characterized by a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">complex cytoplasm in which different regions are poorly defined</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> localization of different regions of the cell into tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">collection of organelles and macromolecular complexes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">simple cytoplasm with well defined regions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prokaryotic cells are characterized by having a simple structure with poorly defined regions. They lack membrane-bound organelles and their genetic material is not contained within a nucleus. This makes their cytoplasm less complex compared to eukaryotic cells.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>1998>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The natural tendency of organisms as they evolve is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease in size</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> increase in number</div>", "<div style=\"font-family:Cambria;font-size:17px;\">develop specialize structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feed indiscriminately</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As organisms evolve, they tend to develop more specialized structures. This is a process known as differentiation, which allows organisms to adapt to their environment and perform specific functions more efficiently.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>1998>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In snails, the hard calcareous shells are secreted by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">radula</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tenidium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pneumostome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mantle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In snails, the hard calcareous shells are secreted by the mantle. The mantle is a specialized tissue that produces the shell by secreting calcium carbonate, which hardens to form the shell.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1998>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structure labelled I is formed as a result of the fusion of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">two pairs of nuclei</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> several pairs of nuclei</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a pair of nuclei</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two pairs of nucleoli</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure labelled I is formed as a result of the fusion of several pairs of nuclei</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>1998>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The special name of the part labelled II is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gametangium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypha</div>", "<div style=\"font-family:Cambria;font-size:17px;\">suspensor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zygospore</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In fungi, suspensors are filamentous structural formations having the function of holding a zygospore between two strains of hyphae. <br/> The labeling (i) is the zygospore <br/> The labeling (II) is the suspensor. <br/> The hypha is the vertical line from your image from which the suspensor arises. <br/> <img src=\"1998/4DR764.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> </div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>1998>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of the cockroach to live in cracks and crevices is enhanced by the possession of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wings and segmented body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compound eyes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">claws on the leg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dorso-ventrally flattened body</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of the cockroach to live in cracks and crevices is enhanced by the possession of a dorso-ventrally flattened body. This body shape allows them to squeeze into small spaces and hide in cracks and crevices. The other options like wings and segmented body, compound eyes, and claws on the leg do not directly contribute to their ability to live in cracks and crevices.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1998>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The caste of termites that lacks pigmentation is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">King</div>", "<div style=\"font-family:Cambria;font-size:17px;\">worker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soldier</div>", "<div style=\"font-family:Cambria;font-size:17px;\">queen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a termite colony, the worker caste lacks pigmentation. Workers are usually the smallest of the castes in a colony, and they are responsible for constructing and maintaining the nest, foraging for food, and caring for the young. The king, soldier, and queen castes have pigmentation.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>1998>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The structure that prevents food particle from escaping through the fish gills are called gill</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">arches</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filaments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rakers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lamellae</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure that prevents food particles from escaping through the fish gills are called gill rakers. Gill rakers are comb-like structures that trap and filter out food particles from the water before it passes over the gills. The other options like gill arches, filaments, and lamellae are parts of the gill structure but do not serve the function of preventing food particles from escaping.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BONY FISH"}, {"id": "objective>Biology>1998>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A distinguished feature of mammals is the possession of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hair</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mammals are the only group of animals that have hair. Hair provides insulation, camouflage, sensory input, and a means of communication.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>1998>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following structures is capable of producing more tissues in the stem of a herbaceous flowering plant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Epidermis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pericycle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Xylem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cambium</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cambium is a type of plant tissue located between the xylem and the phloem in the stem and along the roots of a plant. It is responsible for secondary growth in stems and roots (the thickening of the stem and roots), which produces wood and bark.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>1998>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The manufacture of carbohydrates by plants takes place only in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> the leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the green stems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorophyllous parts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flowering plants</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis, the process by which plants manufacture carbohydrates, requires chlorophyll. Chlorophyll is the green pigment found in chloroplasts of plant cells that absorbs light energy for photosynthesis. Therefore, any part of the plant that contains chlorophyll can manufacture carbohydrates.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>1998>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a water culture experiment, a plant showed poor growth and yellowing of the leaves. These may be due to deficiency in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The symptoms described in the question are typical of a magnesium deficiency in plants. Magnesium is a vital component of chlorophyll, the molecule that absorbs sunlight for photosynthesis. Without sufficient magnesium, the plant cannot produce enough chlorophyll, leading to yellowing of the leaves (chlorosis) and poor growth.</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>1998>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In million's test, when the reagent is added to a protein food item, a white precipitate is produced which turns</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">blue on heating</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> yellow on heating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">green on heating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">red on heating</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Million's test, a protein food item is tested by adding a reagent. If a white precipitate is produced, it turns brick-red colour on heating. This confirms the presence of proteins.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>1998>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Regulation of blood sugar level takes place in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pancreas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iluem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kidney</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The regulation of blood sugar level takes place in the pancreas. The pancreas produces two hormones, insulin and glucagon, which work together to maintain a steady level of glucose, or sugar, in the blood. Insulin decreases the level of glucose in the blood, while glucagon increases it.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>1998>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Unicellular organisms transport essential nutrients directly to all parts of their bodies by the process of diffusion because, they have</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a large volume of surface area ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a large surface area to volume ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their bodies immersed in the nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their outer membrane made of cellulose</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unicellular organisms have a large surface area to volume ratio which allows for efficient diffusion of nutrients throughout the organism. Diffusion is the process by which molecules move from an area of higher concentration to an area of lower concentration. In the case of unicellular organisms, this means that nutrients can easily and quickly reach all parts of the organism.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>1998>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The heart of the adult frog consist of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">two auricles and two ventricles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one auricle and one ventricle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two ventricle and one auricle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one ventricle and two auricles</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The heart of an adult frog consists of one ventricle and two auricles. The ventricle is the chamber of the heart that pumps blood out of the heart, while the auricles (also known as atria in mammals) are the chambers where blood enters the heart.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : TOAD"}, {"id": "objective>Biology>1998>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In adult mammalian blood, the cells which lack nuclei are the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">erythrocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lymphocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">leucocytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phagocytes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In adult mammalian blood, the cells which lack nuclei are the erythrocytes, also known as red blood cells. These cells lack nuclei and other organelles in order to maximize space for hemoglobin, the protein that binds to oxygen and allows erythrocytes to transport oxygen throughout the body.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1998>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following movements occur during exhalation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The diaphragm and intercostal muscles relax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The thoracic cavity increases in volume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The diaphragm and intercostal muscles contract</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The diaphragm contracts and the intercostal muscle relax</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During exhalation, the diaphragm and intercostal muscles relax. This causes the thoracic cavity to decrease in volume, increasing the pressure and forcing air out of the lungs. Therefore, option 1 is correct.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>1998>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following groups of animals is the malpighian tubule found?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lizards, snakes and frogs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Crickets, houseflies and grasshoppers</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Millipedes, centipedes and scorpions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earthworms, roundworms and flatworms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Malpighian tubules are found in insects and are used for the removal of nitrogenous wastes. They are not found in reptiles, amphibians, or worms. Therefore, the correct answer is option 2, which includes crickets, houseflies, and grasshoppers, all of which are insects.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>1998>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a function of the mammalian skeleton?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Protection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Support</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mammalian skeleton serves several functions including support, protection, and aiding movement. However, it does not play a direct role in transpiration. </div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>1998>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The ovary represented is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">half-superior</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inferior</div>", "<div style=\"font-family:Cambria;font-size:17px;\">superior</div>", "<div style=\"font-family:Cambria;font-size:17px;\">half-inferior</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">inferior: Refers to an ovary that is below the attachment of the petals, sepals and stamens. The hypanthium may be fused to the ovary wall or attached to the top of the ovary.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>1998>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The corolla is partly represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I-In plants, the term \"corolla\" refers to a collection of petals that strongly displays colour and encircles the stamen and carpel, the reproductive organs of a flower. Therefore, corolla or petals refers to the second whorl of a flower, which is internal to the calyx.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>1998>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most reliable estimate of growth is by measuring changes in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">length</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dry weight</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most reliable estimate of growth in organisms is by measuring changes in dry weight. This is because dry weight is a measure of the total mass of the organism excluding water. It is a more accurate measure of growth as it takes into account all the components of the organism, including bones, muscles, and organs, unlike length, volume, or surface area which may not accurately reflect the overall growth of the organism.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>1998>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A dry fruit formed from two or more carpels containing several seeds is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">follicle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capsule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">schizocarp</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A dry fruit formed from two or more carpels containing several seeds is a capsule. A capsule is a type of dry fruit that is derived from two or more carpels, and typically contains multiple seeds. Other options like follicle, legume, and schizocarp are also types of dry fruits, but they are not typically formed from two or more carpels or contain multiple seeds.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>1998>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The outermost embryonic membrane in the mammal is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amnion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chorion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allantois</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yolk sac</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The outermost embryonic membrane in mammals is the chorion. The chorion is one of the four main embryonic membranes, and it is the outermost one, forming the fetal part of the placenta in mammals. The other options, amnion, allantois, and yolk sac, are also embryonic membranes, but they are not the outermost.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>1998>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The small masses of nervous tissues in which many neurones have their nuclei are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dorsal roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ventral roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ganglia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synapses</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The small masses of nervous tissues in which many neurons have their nuclei are called ganglia. Ganglia are structures in the nervous system that contain a number of nerve cell bodies. They are found in the peripheral nervous system and are responsible for relaying information to and from the central nervous system.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>1998>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A group of organisms of different species living in a particular area is described as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">colony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">niche</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A group of organisms of different species living in a particular area is described as a community. In ecology, a community is an assemblage of populations of different species, interacting with one another. It differs from a population, which refers to individuals of a single species, and from a colony, which refers to individuals of the same species living closely together.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>1998>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the direct consequence of transferring energy from one trophic level to another?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An increase in biomass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in the efficiency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the total numbers of resulting individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in the resulting biomass</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The direct consequence of transferring energy from one trophic level to another is a decrease in the resulting biomass. This is due to the fact that not all energy is transferred from one trophic level to the next. Some energy is lost as heat, and some is used by the organisms for their own metabolic processes. As a result, the biomass (the total mass of organisms) decreases as you move up the trophic levels.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>1998>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The condition that encourages denitrification is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low soil oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high soil nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of soil bacteria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lightening and thunderstorm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Denitrification is the process by which nitrate (NO<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3-</span>) in the soil is reduced by bacteria to form nitrogen gas (N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), which is then released into the atmosphere. This process is anaerobic, meaning it occurs in the absence of oxygen. Therefore, low soil oxygen encourages denitrification.</div>", "topic": "ECOLOGY : NUTRIENT CYCLING IN NATURE"}, {"id": "objective>Biology>1998>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fresh water plant such as water lily can solve the problem of buoyancy by the possession of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aerenchymatous tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissected leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thin cell walls of the epidermis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water-repelling epidermis</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aerenchyma is a type of plant tissue that contains large air spaces, which provide a low-resistance internal pathway for the exchange of gases such as oxygen and ethylene between the plant above the water and the submerged tissues. This helps the plant to float or maintain buoyancy in water. Therefore, a fresh water plant such as water lily can solve the problem of buoyancy by the possession of aerenchymatous tissues.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1998>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sequence of the biomes in Nigeria from port Harcourt to Damaturu is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">estuarine → rain forest → Guinea Savannah → Sahel Savannah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rain forest → Guinea savannah → estuarine → desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">estuarine → Guinea savannah → rain forest → Sahel savannah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rain forest → estuarine → Guinea savannah → desert</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Biomes are large ecological areas on the earth's surface, with fauna and flora (animals and plants) adapting to their environment. In Nigeria, moving from Port Harcourt (located in the south) to Damaturu (located in the north), the sequence of biomes is as follows: estuarine (near the coast), rain forest (further inland), Guinea Savannah (even further inland), and Sahel Savannah (in the far north, near the Sahara desert). Therefore, the correct sequence is estuarine → rain forest → Guinea Savannah → Sahel Savannah.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : TROPICAL RAINFOREST~~LOCAL(NIGERIAN) BIOMES : GUINEA SAVANNA"}, {"id": "objective>Biology>1998>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil micro-organisms are beneficial because of their involvement in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">translocation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cycling of nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration using soil air</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil micro-organisms are beneficial because they play a crucial role in the cycling of nutrients. They help in the decomposition of organic matter and the release of nutrients into the soil, which can then be used by plants. This process is not related to photosynthesis, translocation, or respiration using soil air.</div>", "topic": "ECOLOGY : NUTRIENT CYCLING IN NATURE"}, {"id": "objective>Biology>1998>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups of diseases are associated with water? I Onchocerciasis II Schistosomiasis III Dracunculiasis IV Elephantiasis V Taeniasis</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, IV and V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Onchocerciasis, Schistosomiasis, and Dracunculiasis are all diseases that are associated with water. Onchocerciasis is caused by a parasitic worm that is transmitted through the bite of infected blackflies that breed in fast-flowing rivers. Schistosomiasis is caused by parasitic worms that live in certain types of freshwater snails. Dracunculiasis, also known as Guinea worm disease, is caused by a parasitic worm that people get from drinking unfiltered water containing tiny water fleas infected with the larvae of the Guinea worm.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>1998>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the ways which body cells differ from gamete cells is in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">type of centromeres they contain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of chromosomes pairs they contain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">type of chromatids they contain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of chromosomes they contain</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Body cells, also known as somatic cells, differ from gamete cells in the number of chromosomes they contain. Body cells are diploid, meaning they contain two sets of chromosomes, one from each parent. On the other hand, gamete cells, which are the reproductive cells (sperm and egg), are haploid, meaning they contain only one set of chromosomes. The type of centromeres, chromatide they contain do not differentiate body cells from gamete cells, and the concept of 'chromosome pairs' is not applicable to gamete cells as they are haploid.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>1998>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In blood transfusion, agglutination occurs when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">white blood cells from two individuals meet</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> two different antibodies meet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two different antigens meet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contrasting antigens and antibodies meet</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agglutination in blood transfusion occurs when contrasting antigens and antibodies meet. Antigens are substances that can trigger an immune response, causing the production of an antibody as part of the body's defense against infection and disease. Antibodies are proteins produced by the immune system to neutralize or destroy antigens. If the antigens in the donor blood and the antibodies in the recipient blood are incompatible, agglutination (clumping of cells) occurs, which can be fatal.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>1998>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the graph below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The unrestricted pattern is represented by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The unrestricted pattern in the graph is represented by II.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>1998>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the graph below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The line that represents efficient recycling combined with stringent conservation is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The line that represents efficient recycling combined with stringent conservation is IV</div>", "topic": "HUMANS AND ENVIRONMENT : CONSERVATION OF NATURAL RESOURCES"}, {"id": "objective>Biology>1998>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">After one week of life, the weight of five chicks of the same sex hatched simultaneously from the eggs of the same hen and fed on the same diet were 45g, 40g, 35g, 33g and 30g. This is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">growth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural selection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The differences in weight among the chicks, despite being of the same sex, hatched simultaneously from the eggs of the same hen and fed on the same diet, is an example of variation. Variation refers to the differences in physical or genetic characteristics between individuals within the same species. These differences can be due to genetic factors, environmental factors, or a combination of both.</div>", "topic": "VARIATION IN POPULATION : APPLICATION OF VARIATION"}, {"id": "objective>Biology>1998>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The phenotype of an individual can be summed up as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">totality of the expressed traits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">individual's physical appearance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">individual's entire genetical make-up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physiological traits of individual</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phenotype of an individual refers to the observable physical properties of an organism; these include the organism's appearance, development, and behavior. The totality of the expressed traits is the phenotype.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>1998>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct increasing order of size for the cell components responsible for heredity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chromosome → DNA → nucleus → gene</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> DNA → gene → chromosome → nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> chromosome → nucleus → DNA → gene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">DNA → gene → nucleus → chromosome</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct increasing order of size for the cell components responsible for heredity is DNA → gene → chromosome → nucleus. DNA (Deoxyribonucleic acid) is the smallest unit and it forms the genes. Genes are segments of DNA that carry hereditary information and are located on chromosomes. Chromosomes are located inside the nucleus of the cell, which is the largest of the four.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>1998>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sex-linked character cannot be passed on directly from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">father to son</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mother to daughter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mother to son</div>", "<div style=\"font-family:Cambria;font-size:17px;\">father to daughter</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A sex-linked character cannot be passed on directly from father to son. This is because sex-linked traits are located on the X chromosome. Males have one X and one Y chromosome (XY), while females have two X chromosomes (XX). A father passes on his Y chromosome to his son, not his X chromosome, so he cannot pass on X-linked traits directly to his son.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>1998>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The biological association that contributes directly to succession in a community is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">predation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parasitism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commensalism</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The biological association that contributes directly to succession in a community is competition. Succession is the process by which the structure of a biological community evolves over time. Competition between species for resources such as food, water, and space drives this process, as some species become more dominant over time, while others decline or disappear.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>1998>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The group of insects that have mouth parts adapted for both piercing and sucking is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cockroach, aphids and mosquitoes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aphids, houseflies and moths</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mosquitoes, tse-tse flies and aphids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aphids, beetles and grasshoppers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mouthparts of mosquitoes, tse-tse flies, and aphids are adapted for both piercing and sucking. They have a proboscis, a long, slender, tubular feeding and sucking organ, that they use to pierce the skin or plant tissues and suck up the fluids. This is not the case for cockroaches, houseflies, moths, beetles, and grasshoppers.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1998>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The bird's bill adapted for fishing is labelled </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bird's bill adapted for fishing in the diagram is labelled IV,pointed beak</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1998>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Toes of the feet ending in sharp, curved hook suitable for holding and tearing are most likely to belong to the bird with the bill in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Toes of the feet ending in sharp, curved hook suitable for holding and tearing are most likely to belong to the bird with the bill in II</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>1998>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the honey bee colony, the drones are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> sterile males with reduced mouth parts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sterile males with well-developed mouth parts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fertile males with reduced mouth parts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fertile males with well-developed mouth parts</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A drone is a male honey bee. Unlike the female worker bee, drones do not have stingers. They gather neither nectar nor pollen and are unable to feed without assistance from worker bees. A drone's only role is to mate with an unfertilized queen.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>1998>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the whistling pine, leaves are reduced to brown scales and young stems are green. This is an adaptation for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">obtaining food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conserving nutrients</div>", "<div style=\"font-family:Cambria;font-size:17px;\">storing water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing transpiration</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the whistling pine, the leaves are reduced to brown scales and the young stems are green. This is an adaptation for reducing transpiration. Transpiration is the process where plants lose water to the air. By reducing the surface area of the leaves, the plant can conserve water by reducing the amount of water that is lost to the air.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>1998>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best explanation for the theories of natural selection is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all organisms have equal capacity for survival in their habitats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organisms have varying capacities for survival in their habitats</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> organisms compete for resource and better competitors survive and thrive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">habitats allow only organisms that will not have to compete for survival</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of natural selection, also known as survival of the fittest, suggests that species that adapt to their environment are more likely to survive and pass on the genes that aided their success. This process causes species to gradually evolve. Option 3, 'organisms compete for resources and better competitors survive and thrive', best explains this theory as it highlights the competition for resources and survival of the fittest.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>1998>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic point of impact by changes which produce mutation is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gametes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phenotype</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zygote</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mutation is a change that occurs in our DNA sequence, either due to mistakes when the DNA is copied or as the result of environmental factors such as UV light and cigarette smoke. Mutations can occur in both the gametes and the somatic cells. However, only mutations that occur in the gametes can be passed on to offspring. Therefore, the basic point of impact by changes which produce mutation is the chromosomes, which are part of every cell, including gametes.</div>", "topic": "HEREDITY : CHROMOSOMES"}];
